async (params, browser) => {
  // Search Amazon
  await browser.open(`https://www.amazon.com/s?k=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('.s-result-item[data-asin], [data-component-type=\'s-search-result\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract product results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('.s-result-item[data-asin]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const asin = el.getAttribute('data-asin'); if (!asin) continue; const titleEl = el.querySelector('h2 a span, h2 span.a-text-normal'); const linkEl = el.querySelector('h2 a.a-link-normal'); const priceWhole = el.querySelector('.a-price .a-offscreen'); const ratingEl = el.querySelector('.a-icon-star-small .a-icon-alt, i.a-icon-star-small .a-icon-alt'); const reviewCountEl = el.querySelector('a[href*="#customerReviews"] span.a-size-base, a[href*="customerReviews"] span, .a-size-small .a-link-normal .a-size-base'); const primeEl = el.querySelector('.a-icon-prime, [data-a-badge-type="deal"], .s-prime'); const imgEl = el.querySelector('img.s-image'); const url = linkEl ? 'https://www.amazon.com' + linkEl.getAttribute('href') : ''; results.push({ title: titleEl ? titleEl.textContent.trim() : '', price: priceWhole ? priceWhole.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', has_prime: !!primeEl, image: imgEl ? imgEl.getAttribute('src') : '', url: url, asin: asin }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
